import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../../api/api";

// ✅ MASTER CATEGORY LIST — same values in PostProject + MyProjects + FindProjects
export const CATEGORIES = [
  { value: "web-development",     label: "Web Development"    },
  { value: "mobile-development",  label: "Mobile Development" },
  { value: "ui-ux-design",        label: "UI/UX Design"       },
  { value: "graphic-design",      label: "Graphic Design"     },
  { value: "backend-development", label: "Backend Development"},
  { value: "data-science",        label: "Data Science & ML"  },
  { value: "devops-cloud",        label: "DevOps / Cloud"     },
  { value: "content-writing",     label: "Content Writing"    },
  { value: "digital-marketing",   label: "Digital Marketing"  },
  { value: "video-editing",       label: "Video Editing"      },
  { value: "seo",                 label: "SEO"                },
  { value: "cybersecurity",       label: "Cybersecurity"      },
  { value: "other",               label: "Other"              },
];

export const getCategoryLabel = (value) =>
  CATEGORIES.find(c => c.value === value)?.label || value || "Other";

export default function PostProject() {
  const navigate = useNavigate();
  const [form, setForm] = useState({
    title: "", description: "", budget: "",
    category: "", skills: "", deadline: "",
  });
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState("");
  const [success, setSuccess] = useState("");

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(""); setSuccess("");
    if (!form.title || !form.description || !form.budget || !form.category) {
      setError("Please fill all required fields including category.");
      return;
    }
    setLoading(true);
    try {
      await API.post("/projects", {
        title:       form.title,
        description: form.description,
        budget:      form.budget,
        category:    form.category,
        skills:      form.skills,
        deadline:    form.deadline || null,
      });
      setSuccess("Project posted successfully!");
      setTimeout(() => navigate("/client/my-projects"), 1500);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to post project.");
    }
    setLoading(false);
  };

  const inp = { width:"100%", padding:"10px 14px", border:"1.5px solid #e2e8f0", borderRadius:"8px", fontSize:"13px", outline:"none", background:"white", color:"#0f172a", boxSizing:"border-box" };
  const lbl = { fontSize:"12px", fontWeight:"600", color:"#374151", display:"block", marginBottom:"5px" };

  return (
    <div style={{ background:"#f8fafc", minHeight:"100vh", padding:"32px", fontFamily:"'Segoe UI',sans-serif" }}>
      <div style={{ maxWidth:"640px", margin:"0 auto" }}>
        <h1 style={{ fontSize:"24px", fontWeight:"700", color:"#0f172a", margin:"0 0 4px" }}>Post a Project</h1>
        <p style={{ color:"#64748b", fontSize:"13px", marginBottom:"28px" }}>Fill in the details to find the right freelancer</p>

        {error   && <div style={{ background:"#fff1f2", border:"1px solid #fecdd3", color:"#dc2626", padding:"12px 16px", borderRadius:"10px", marginBottom:"16px", fontSize:"13px" }}>⚠️ {error}</div>}
        {success && <div style={{ background:"#dcfce7", border:"1px solid #86efac", color:"#15803d", padding:"12px 16px", borderRadius:"10px", marginBottom:"16px", fontSize:"13px" }}>✅ {success}</div>}

        <div style={{ background:"white", border:"1px solid #e2e8f0", borderRadius:"16px", padding:"28px", boxShadow:"0 1px 4px rgba(0,0,0,0.04)" }}>
          <form onSubmit={handleSubmit}>

            <div style={{ marginBottom:"18px" }}>
              <label style={lbl}>Project Title <span style={{ color:"#ef4444" }}>*</span></label>
              <input name="title" value={form.title} onChange={handleChange} placeholder="e.g. Build a React dashboard" style={inp} required />
            </div>

            <div style={{ marginBottom:"18px" }}>
              <label style={lbl}>Description <span style={{ color:"#ef4444" }}>*</span></label>
              <textarea name="description" value={form.description} onChange={handleChange}
                placeholder="Describe what you need..." rows={4}
                style={{ ...inp, resize:"none", lineHeight:1.6 }} required />
            </div>

            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"16px", marginBottom:"18px" }}>
              <div>
                <label style={lbl}>Budget (₹) <span style={{ color:"#ef4444" }}>*</span></label>
                <input name="budget" type="number" value={form.budget} onChange={handleChange} placeholder="e.g. 5000" style={inp} required />
              </div>
              <div>
                <label style={lbl}>Category <span style={{ color:"#ef4444" }}>*</span></label>
                <select name="category" value={form.category} onChange={handleChange}
                  style={{ ...inp, cursor:"pointer" }} required>
                  <option value="">-- Select Category --</option>
                  {CATEGORIES.map(c => (
                    <option key={c.value} value={c.value}>{c.label}</option>
                  ))}
                </select>
              </div>
            </div>

            <div style={{ marginBottom:"18px" }}>
              <label style={lbl}>Required Skills <span style={{ color:"#94a3b8", fontWeight:"400" }}>(optional, comma separated)</span></label>
              <input name="skills" value={form.skills} onChange={handleChange} placeholder="e.g. React, Node.js, MySQL" style={inp} />
            </div>

            <div style={{ marginBottom:"24px" }}>
              <label style={lbl}>Deadline <span style={{ color:"#94a3b8", fontWeight:"400" }}>(optional)</span></label>
              <input name="deadline" type="date" value={form.deadline} onChange={handleChange} style={inp} />
            </div>

            <div style={{ display:"flex", gap:"12px" }}>
              <button type="submit" disabled={loading}
                style={{ flex:1, padding:"12px", borderRadius:"10px", border:"none", background:"linear-gradient(135deg,#0f766e,#0891b2)", color:"white", fontSize:"14px", fontWeight:"700", cursor:loading?"not-allowed":"pointer", opacity:loading?0.7:1 }}>
                {loading ? "Posting..." : "🚀 Post Project"}
              </button>
              <button type="button" onClick={() => navigate("/client/my-projects")}
                style={{ padding:"12px 20px", borderRadius:"10px", border:"1px solid #e2e8f0", background:"white", color:"#64748b", fontSize:"14px", fontWeight:"600", cursor:"pointer" }}>
                Cancel
              </button>
            </div>

          </form>
        </div>
      </div>
    </div>
  );
}
